@layer mergora.components {
  .mrg-reasoning {
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
    overflow: clip;
  }

  .mrg-reasoning [data-slot="reasoning-summary"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-md);
    min-block-size: var(--mrg-semantic-size-target-minimum);
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-surface);
    font-weight: var(--mrg-semantic-font-weight-label);
    cursor: pointer;
  }

  .mrg-reasoning [data-slot="reasoning-summary"] span:last-child {
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    font-size: var(--mrg-semantic-font-size-caption);
  }

  .mrg-reasoning [data-slot="reasoning-summary"]:focus-visible {
    box-shadow: inset 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: calc(var(--mrg-semantic-focus-offset) * -1);
  }

  .mrg-reasoning [data-slot="reasoning-progress"] {
    margin: 0;
    padding: var(--mrg-semantic-space-inset-xs) var(--mrg-semantic-space-inset-md);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-accent-border);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    background: var(--mrg-semantic-color-accent-background-subtle);
    font-size: var(--mrg-semantic-font-size-label);
  }

  .mrg-reasoning [data-slot="reasoning-content"] {
    padding: var(--mrg-semantic-density-panel-padding);
    line-height: var(--mrg-semantic-font-line-height-body);
    overflow-wrap: anywhere;
  }

  .mrg-reasoning [data-slot="reasoning-announcement"] {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-reasoning * {
      scroll-behavior: auto;
      transition-duration: var(--mrg-semantic-motion-duration-reduced);
    }
  }

  @media (forced-colors: active) {
    .mrg-reasoning,
    .mrg-reasoning [data-slot="reasoning-summary"],
    .mrg-reasoning [data-slot="reasoning-progress"] {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-reasoning [data-slot="reasoning-summary"]:focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

"use client";

import "./reasoning.css";

import {
  forwardRef,
  useEffect,
  useRef,
  useState,
  type DetailsHTMLAttributes,
  type ReactNode,
} from "react";

export type ReasoningStatus = "complete" | "error" | "idle" | "streaming";

export interface ReasoningProgress {
  /** Completed integer units, constrained between zero and `total`. */
  readonly completed: number;
  /** Optional visible name for the progress measure, defaulting to `Progress`. */
  readonly label?: string;
  /** Positive integer number of units required for completion. */
  readonly total: number;
}

export interface ReasoningProps extends Omit<
  DetailsHTMLAttributes<HTMLDetailsElement>,
  "children" | "onToggle" | "open"
> {
  /** Announces a streaming-to-complete transition; false removes the live region and announcement updates. */
  readonly announceCompletion?: boolean;
  /** Reasoning detail content revealed by the native disclosure. */
  readonly children: ReactNode;
  /** Localized polite announcement used when enabled reasoning completes. */
  readonly completionAnnouncement?: string;
  /** Initial native disclosure state for uncontrolled use. */
  readonly defaultOpen?: boolean;
  /** Reports native disclosure changes for controlled or uncontrolled use. */
  readonly onOpenChange?: (open: boolean) => void;
  /** Controlled native disclosure state; omit to use `defaultOpen`. */
  readonly open?: boolean;
  /** Optional bounded progress summary; false removes its UI and associated semantics. */
  readonly progress?: false | ReasoningProgress;
  /** Current reasoning lifecycle reflected in the summary and stable state metadata. */
  readonly status?: ReasoningStatus;
  /** Required concise label rendered inside the native disclosure summary. */
  readonly summary: ReactNode;
}

export const Reasoning = forwardRef<HTMLDetailsElement, ReasoningProps>(function Reasoning(
  {
    announceCompletion = false,
    children,
    className,
    completionAnnouncement = "Reasoning summary is complete.",
    defaultOpen = false,
    onOpenChange,
    open,
    progress = false,
    status = "idle",
    summary,
    ...props
  },
  ref,
) {
  const controlled = open !== undefined;
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const currentOpen = controlled ? open : uncontrolledOpen;
  const priorStatus = useRef(status);
  const [announcement, setAnnouncement] = useState("");
  if (
    progress !== false &&
    (!Number.isSafeInteger(progress.completed) ||
      !Number.isSafeInteger(progress.total) ||
      progress.total < 1 ||
      progress.completed < 0 ||
      progress.completed > progress.total)
  ) {
    throw new RangeError("Mergora Reasoning progress must be safe integers within total.");
  }

  useEffect(() => {
    if (announceCompletion && priorStatus.current === "streaming" && status === "complete") {
      setAnnouncement(completionAnnouncement);
    }
    priorStatus.current = status;
  }, [announceCompletion, completionAnnouncement, status]);

  return (
    <details
      {...props}
      className={className === undefined ? "mrg-reasoning" : `mrg-reasoning ${className}`}
      data-slot="reasoning"
      data-status={status}
      onToggle={(event) => {
        const next = event.currentTarget.open;
        if (!controlled) setUncontrolledOpen(next);
        onOpenChange?.(next);
      }}
      open={currentOpen}
      ref={ref}
    >
      <summary data-slot="reasoning-summary">
        <span>{summary}</span>
        <span>{status}</span>
      </summary>
      {progress === false ? null : (
        <p data-slot="reasoning-progress">
          {progress.label ?? "Progress"}: {progress.completed} of {progress.total}
        </p>
      )}
      <div data-slot="reasoning-content">{children}</div>
      {announceCompletion ? (
        <span aria-live="polite" data-slot="reasoning-announcement">
          {announcement}
        </span>
      ) : null}
    </details>
  );
});

Reasoning.displayName = "Reasoning";
